#include<bits/stdc++.h>
using namespace std;
long long b[30][100005],n,q;
void init(){
	for(int i=1;i<=20;i++){
		for(int j=1;j+(1<<i)<=n+1;j++){
            b[i][j]=min(b[i-1][j],b[i-1][j+(1<<(i-1))]);
		}
	}
}
long long find(int l,int r){
    int k=0;
    while((1 << (k+1)) <= r-l+1) k++;
	return min(b[k][l],b[k][r-(1<<k)+1]);
}
int main(){

	cin>>n>>q;
	for(int i=1;i<=n;i++){
		cin>>b[0][i];
	}
    init();
	for(int i=1;i<=q;i++){
		int x,y;
		cin>>x>>y;
		cout<<find(x,y)<<" ";
	}
	return 0;
}
